PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?team ?year2
WHERE {
  ?sb1 wdt:P31 wd:Q148358;
        wdt:P585 ?date1;
        wdt:P168 ?team.
  ?sb2 wdt:P31 wd:Q148358;
        wdt:P585 ?date2;
        wdt:P168 ?team.
  BIND(YEAR(?date1) AS ?year1)
  BIND(YEAR(?date2) AS ?year2)
  FILTER(?year2 = ?year1 + 1)
}
ORDER BY DESC(?year2)
LIMIT 1

